provider "aws" {
   access_key = "AWS ACCESS KEY"
   secret_key = "AWS SECRET KEY"
   region = "AWS REGION"
}

resource "ibm_lb" "${myResourceName}" {
   connections = 
   datacenter    = ""
   ha_enabled  = false
   dedicated = true
}

data "aws_ami" "${ami-name}" {
	most_recent = true
	executable_users = ["self"]
	filter {
		name = "owner-alias"
		values = ["amazon"]
	}
	filter {
		name = "name"
		values = ["amzn-ami-vpc-nat*"]
	}
	owners = ["self"]
}

variable "vpc_id" {}

data "aws_vpc" "${selected}" {
   id = "\${var.vpc_id}"
}

resource "aws_subnet" "example" {
    vpc_id            = "\${data.aws_vpc.${selected}.id}"
    availability_zone = "us-west-2a"
    cidr_block        = "\${cidrsubnet(data.aws_vpc.${selected}.cidr_block, 4, 1)}"
}

resource "random_id" "${myResourceName}" {
   name = "my-${myResourceName}"
   keepers = {
       # Generate a new id each time we switch to a new AMI id
       ami_id = "${var.ami_id}"
   }
   byte_length = 8
}

variable "subnet_id" {}

data "aws_subnet" "${selected}" {
    id = "\${var.subnet_id}"
}

resource "aws_security_group" "subnet" {
    vpc_id = "\${data.aws_subnet.${selected}.vpc_id}"

    ingress {
        cidr_blocks = ["\${data.aws_subnet.${selected}.cidr_block}"]
        from_port   = 80
        to_port     = 80
        protocol    = "tcp"
    }
}

resource "clc_server" "${myResourceName}" {
   name = "my-${myResourceName}"
   description = "my-description-${myResourceName}"
   source_server_id = "UBUNTU-14-64-TEMPLATE"
   group_id = "\${clc_group.frontends.id}"
   cpu = 2
   memory_mb = 2048
   password = "Green123$"
   additional_disks {
       path = "/var"
       size_gb = 100
       type = "partitioned"
   }

   additional_disks {
       size_gb = 10
       type = "raw"
   }
}

data "terraform_remote_state" "${myBackend}" {
   backend = "s3"
   config {
       bucket = "terraform-state-prod"
       key = "network/terraform.tfstate"
       region = "us-east-1"
   }
}

provider "aws" {
   region = "${1:AWS REGION}"
   shared_credentials_file = "${2:path/to/.aws/creds}"
   profile = "${3:AWS PROFILE}"
}

data "terraform_remote_state" "${myBackend}" {
   backend = "gcs"
   config {
       bucket = "terraform-state-prod"
       path = "network/terraform.tfstate"
       project = "goopro"
   }
}

resource "rundeck_job" "${myResourceName}" {
   name = "my-${myResourceName}"
   description = "my-description-${myResourceName}"

   project_name = "anvils"
   node_filter_query = "tags: web"
   command {
       shell_command = "sudo service anvils restart"
   }
}

resource "vcd_network" "${myResourceName}" {
   name = "my-${myResourceName}"
   description = "my-description-${myResourceName}"

   edge_gateway = "Edge Gateway Name"
   gateway = "10.10.0.1"
   dhcp_pool {
       start_address = "10.10.0.2"
       end_address = "10.10.0.100"
   }
   static_ip_pool {
       start_address = "10.10.0.152"
       end_address = "10.10.0.254"
   }
}

data "terraform_remote_state" "${myBackend}" {
   backend = "etcd"
   config {
       path = "path/to/terraform.tfstate"
       endpoints = "http://one:4001 http://two:4001"
   }
}

resource "vault_policy" "${1:vault_policy_id}" {
   name = "${2:myPath}"
   policy = <<EOT
path "${3:secret/my_app}" {
   policy = "${4:write}"
}
EOT
}

data "aws_ip_ranges" "${european_ec2}" {
   regions = [ "eu-west-1", "eu-central-1" ]
   services = [ "ec2" ]
}

resource "aws_security_group" "from_europe" {
   name = "from_europe"

   ingress {
       from_port = "443"
       to_port = "443"
       protocol = "tcp"
       cidr_blocks = [ "\${data.aws_ip_ranges.${european_ec2}.cidr_blocks}" ]
   }

   tags {
       CreateDate = "\${data.aws_ip_ranges.${european_ec2}.create_date}"
       SyncToken = "\${data.aws_ip_ranges.${european_ec2}.sync_token}"
   }

}

data "terraform_remote_state" "${myBackend}" {
   backend = "azure"
   config {
       storage_account_name = "terraform123abc"
       container_name = "terraform-state"
       key = "prod.terraform.tfstate"
   }
}

resource "clc_public_ip" "${myResourceName}" {
   name = "my-${myResourceName}"
   description = "my-description-${myResourceName}"
   server_id = "\${clc_server.node.0.id}"
   internal_ip_address = "${clc_server.node.0.private_ip_address}"
   ports {
       protocol = "ICMP"
       port = -1
   }

   ports {
       protocol = "TCP"
       port = 22
   }

   ports {
       protocol = "TCP"
       port = 2000
       port_to = 9000
   }

   source_restrictions {
       cidr = "85.39.22.15/30"
   }
}

data "ibm_app_domain_shared" "${myResourceName}" {
   name        = ""
}
resource "ibm_app_route" "${myResourceName}-route" {
   domain_guid       = "${data.ibm_app_domain_shared.myResourceName-domain.id}"
   space_guid        = "${data.ibm_space.myResourceName-space.id}"
   host              = "myHost"
   path              = "/app"
}

resource "influxdb_user" "${myResourceName}" {
   name = "my-${myResourceName}"
   description = "my-description-${myResourceName}"

   password = "super-secret"

   grant {
       database = "\${influxdb_database.green.name}"
       privilege = "write"
   }
}

resource "librato_alert" "${myResourceName}" {
   name = "my-${myResourceName}"
   description = "my-description-${myResourceName}"

   services = [ "\${librato_service.myservice.id}" ]
   condition {
       type = "above"
       threshold = 10
       metric_name = "librato.cpu.percent.idle"
   }
}

resource "packet_volume" "${myResourceName}" {
   name = "my-${myResourceName}"
   description = "my-description-${myResourceName}"

   facility = "ewr1"
   project_id = "\${packet_project.cool_project.id}"
   plan = "storage_1"
   size = 100
   billing_cycle = "hourly"
   snapshot_policies = { snapshot_frequency = "1day", snapshot_count = 7 }
   snapshot_policies = { snapshot_frequency = "1month", snapshot_count = 6 }
}

data "atlas_artifact" "${web}" {
   name = "hashicorp/web"
   type = "amazon.image"
   build = "latest"
   metadata {
       arch = "386"
   }
}

data "aws_ebs_volume" "${ebs_volume}" {
    most_recent = true
    filter {
        name = "volume-type"
        values = ["gp2"]
    }
    filter {
        name = "tag:${Name}"
        values = ["${Example}"]
    }
}

resource "cloudstack_vpc" "${myResourceName}" {
   name = "my-${myResourceName}"
   cidr = "10.0.0.0/16"
   vpc_offering = "Default VPC Offering"
   zone = "zone-1"
}

resource "rabbitmq_queue" "${myResourceName}" {
   name = "my-${myResourceName}"
   description = "my-description-${myResourceName}"

   vhost = "\${rabbitmq_permissions.guest.vhost}"
   settings {
       durable = false
       auto_delete = true
   }
}

resource "aws_vpc_endpoint" "${private_s3}" {
    vpc_id = "\${aws_vpc.foo.id}"
    service_name = "com.amazonaws.us-west-2.s3"
}

data "aws_prefix_list" "${private_s3}" {
   prefix_list_id = "\${aws_vpc_endpoint.${private_s3}.prefix_list_id}"
}

resource "aws_network_acl" "${bar}" {
    vpc_id = "\${aws_vpc.foo.id}"
}

resource "aws_network_acl_rule" "${private_s3}" {
    network_acl_id = "\${aws_network_acl.${bar}.id}"
    rule_number = 200
